const BUYER_PROPERTY_TYPE_OPTIONS = [
  '',
  'House',
  'Townhouse',
  'Apartment',
  'Cluster',
  'Duplex',
  'Vacant Land',
  'Commercial',
  'Other',
]

const BUYER_CURRENT_PROPERTY_OPTIONS = [
  { value: '', label: 'Unknown' },
  { value: 'First-time buyer', label: 'First-time buyer' },
  { value: 'Renting', label: 'Renting' },
  { value: 'Owns property', label: 'Owns property' },
  { value: 'Selling current property', label: 'Selling current property' },
  { value: 'Investor', label: 'Investor' },
]

function normalizeMoneyInput(value) {
  return String(value || '').replace(/[^\d]/g, '')
}

function normalizeNumericInput(value) {
  const cleaned = String(value || '').replace(/[^\d.]/g, '')
  const [whole, ...decimalParts] = cleaned.split('.')
  return decimalParts.length ? `${whole}.${decimalParts.join('')}` : whole
}

function BuyerProfileCard({ row, requirement, organisationId, actor, onSaved, focusSignal = 0, onRecommendations, onBondPartnerReferral }) {
  const [sendingBondReferral, setSendingBondReferral] = useState(false)
  const [bondReferralError, setBondReferralError] = useState('')
  const [editing, setEditing] = useState(false)
  const [saving, setSaving] = useState(false)
  const [saveError, setSaveError] = useState('')
  const [optimisticRequirement, setOptimisticRequirement] = useState(null)
  const cardRef = useRef(null)
  const displayRequirement = optimisticRequirement || requirement
  const buildDraft = useCallback(() => ({
    ...makeRequirementDraft(displayRequirement, row),
    isPrimary: displayRequirement?.requirementId ? Boolean(displayRequirement.isPrimary ?? displayRequirement.is_primary) : true,
  }), [displayRequirement, row])
  const [draft, setDraft] = useState(() => buildDraft())
  const showBondReferral = shouldShowBondReferralPrompt(row, displayRequirement)
  const profileRows = [
    { icon: Banknote, label: 'Budget', value: getBuyerBudgetLabel(row, displayRequirement) },
    { icon: CreditCard, label: 'Finance', value: getBuyerFinancePositionLabel(row, displayRequirement) },
    { icon: BadgeCheck, label: 'Pre Qualified', value: getBuyerPreQualifiedLabel(displayRequirement) },
    { icon: Home, label: 'Property Type', value: getBuyerPropertyTypeLabel(row, displayRequirement) },
    { icon: Home, label: 'Bedrooms', value: getBuyerBedroomLabel(row, displayRequirement) },
    { icon: Shield, label: 'Bathrooms', value: getBuyerBathroomLabel(row, displayRequirement) },
    { icon: MapPin, label: 'Areas', value: getBuyerAreaLabel(row, displayRequirement) },
    { icon: Clock3, label: 'Urgency', value: getBuyerUrgencyLabel(row, displayRequirement) },
    { icon: Building2, label: 'Current Property', value: getBuyerCurrentPropertyLabel(row, displayRequirement) },
    { icon: Tag, label: 'Needs To Sell', value: getBuyerNeedsToSellLabel(row, displayRequirement) },
  ]
  const selectedPropertyType = parseListInput(draft.propertyTypes)[0] || ''
  const propertyTypeOptions = selectedPropertyType && !BUYER_PROPERTY_TYPE_OPTIONS.includes(selectedPropertyType)
    ? [...BUYER_PROPERTY_TYPE_OPTIONS, selectedPropertyType]
    : BUYER_PROPERTY_TYPE_OPTIONS
  const currentPropertyOptions = draft.currentPropertyStatus && !BUYER_CURRENT_PROPERTY_OPTIONS.some((option) => option.value === draft.currentPropertyStatus)
    ? [...BUYER_CURRENT_PROPERTY_OPTIONS, { value: draft.currentPropertyStatus, label: draft.currentPropertyStatus }]
    : BUYER_CURRENT_PROPERTY_OPTIONS

  useEffect(() => {
    setOptimisticRequirement(null)
  }, [requirement?.requirementId, requirement?.updatedAt, requirement?.updated_at])

  useEffect(() => {
    if (!editing) setDraft(buildDraft())
  }, [buildDraft, editing])

  useEffect(() => {
    if (!focusSignal) return
    setEditing(true)
    setSaveError('')
    const runAfterFrame = typeof window !== 'undefined' && window.requestAnimationFrame ? window.requestAnimationFrame : (callback) => callback()
    runAfterFrame(() => {
      cardRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' })
    })
  }, [focusSignal])

  function updateDraftField(field, value) {
    setDraft((current) => ({ ...current, [field]: value }))
  }

  async function saveQualification(event) {
    event?.preventDefault()
    if (!organisationId || !getLeadRecordId(row)) {
      setSaveError('This buyer cannot be updated until the workspace has loaded.')
      return
    }
    try {
      setSaving(true)
      setSaveError('')
      const payload = draftToRequirementPayload(draft, row, organisationId, actor)
      let savedRequirement
      if (displayRequirement?.requirementId) {
        savedRequirement = await updateLeadRequirement({ requirementId: displayRequirement.requirementId, updates: payload }, { actor })
      } else {
        savedRequirement = await createLeadRequirement(payload, { actor })
      }
      setOptimisticRequirement(savedRequirement)
      setEditing(false)
      upsertLeadRequirementAreas(payload).catch((areaError) => {
        console.warn('[BuyerProfileCard] area enrichment skipped', areaError)
      })
      Promise.resolve(onSaved?.()).catch((refreshError) => console.warn('[BuyerProfileCard] background refresh skipped', refreshError))
    } catch (qualificationError) {
      setSaveError(qualificationError?.message || 'Unable to save the qualification snapshot.')
    } finally {
      setSaving(false)
    }
  }

  async function requestBondReferral() {
    if (!onBondPartnerReferral || sendingBondReferral) return
    try {
      setSendingBondReferral(true)
      setBondReferralError('')
      await onBondPartnerReferral()
    } catch (bondError) {
      setBondReferralError(bondError?.message || 'Unable to log the bond partner handoff.')
    } finally {
      setSendingBondReferral(false)
    }
  }

  return (
    <section ref={cardRef} className={`${buyerWorkspaceCardClass} p-5 ${editing ? 'ring-2 ring-blue-100' : ''}`}>
      <div className="flex items-start justify-between gap-3">
        <div>
          <p className="flex items-center gap-2 text-xs font-semibold uppercase tracking-[0.14em] text-blue-600">
            <UserRound size={15} />
            Buyer Profile
          </p>
          <h2 className="mt-2 text-xl font-semibold tracking-[-0.04em] text-slate-950">Qualification snapshot</h2>
        </div>
        {editing ? (
          <div className="flex gap-2">
            <button type="button" onClick={() => { setEditing(false); setSaveError(''); setDraft(buildDraft()) }} disabled={saving} className="inline-flex min-h-9 items-center justify-center rounded-xl border border-slate-200 bg-white px-3 text-sm font-semibold text-slate-700 hover:bg-slate-50 disabled:cursor-not-allowed disabled:opacity-60">
              Cancel
            </button>
            <button type="submit" form="buyer-qualification-inline-form" disabled={saving} className="inline-flex min-h-9 items-center justify-center rounded-xl bg-slate-950 px-3 text-sm font-semibold text-white hover:bg-slate-800 disabled:cursor-not-allowed disabled:bg-slate-400">
              {saving ? 'Saving...' : 'Save'}
            </button>
          </div>
        ) : (
          <button type="button" onClick={() => { setEditing(true); setSaveError('') }} className="inline-flex min-h-9 items-center justify-center rounded-xl border border-slate-200 bg-white px-3 text-sm font-semibold text-slate-700 hover:bg-slate-50">
            Edit
          </button>
        )}
      </div>
      {editing ? (
        <form id="buyer-qualification-inline-form" onSubmit={saveQualification} className="mt-5 grid gap-3">
          <div className="grid gap-3 sm:grid-cols-2">
            <label className="grid gap-1 text-xs font-semibold uppercase tracking-[0.12em] text-slate-400">
              Budget min
              <span className="flex min-h-10 items-center gap-2 rounded-xl border border-slate-200 bg-white px-3 text-sm font-semibold normal-case tracking-normal text-slate-900">
                <span className="text-slate-400">R</span>
                <input value={draft.budgetMin} inputMode="numeric" pattern="[0-9]*" onChange={(event) => updateDraftField('budgetMin', normalizeMoneyInput(event.target.value))} className="min-w-0 flex-1 border-0 bg-transparent p-0 text-sm font-semibold text-slate-900 outline-none" placeholder="2500000" />
              </span>
            </label>
            <label className="grid gap-1 text-xs font-semibold uppercase tracking-[0.12em] text-slate-400">
              Budget max
              <span className="flex min-h-10 items-center gap-2 rounded-xl border border-slate-200 bg-white px-3 text-sm font-semibold normal-case tracking-normal text-slate-900">
                <span className="text-slate-400">R</span>
                <input value={draft.budgetMax} inputMode="numeric" pattern="[0-9]*" onChange={(event) => updateDraftField('budgetMax', normalizeMoneyInput(event.target.value))} className="min-w-0 flex-1 border-0 bg-transparent p-0 text-sm font-semibold text-slate-900 outline-none" placeholder="3500000" />
              </span>
            </label>
          </div>
          <div className="grid gap-3 sm:grid-cols-2">
            <label className="grid gap-1 text-xs font-semibold uppercase tracking-[0.12em] text-slate-400">
              Finance
              <select value={draft.financeStatus} onChange={(event) => updateDraftField('financeStatus', event.target.value)} className="min-h-10 rounded-xl border border-slate-200 bg-white px-3 text-sm font-semibold normal-case tracking-normal text-slate-900">
                {LEAD_REQUIREMENT_FINANCE_STATUSES.map((option) => <option key={option} value={option}>{titleCaseLabel(option.replace(/_/g, ' '))}</option>)}
              </select>
            </label>
            <label className="grid gap-1 text-xs font-semibold uppercase tracking-[0.12em] text-slate-400">
              Pre qualified
              <select value={draft.preApproved} onChange={(event) => updateDraftField('preApproved', event.target.value)} className="min-h-10 rounded-xl border border-slate-200 bg-white px-3 text-sm font-semibold normal-case tracking-normal text-slate-900">
                <option value="">Unknown</option>
                <option value="true">Yes</option>
                <option value="false">No</option>
              </select>
            </label>
          </div>
          <AreaMultiSelect
            value={draft.areas}
            onChange={(areas) => updateDraftField('areas', areas.join(', '))}
            placeholder="Olympus, Faerie Glen"
            description="Select saved Arch9 areas or add a new preference."
          />
          <label className="grid gap-1 text-xs font-semibold uppercase tracking-[0.12em] text-slate-400">
            Property type
            <select value={selectedPropertyType} onChange={(event) => updateDraftField('propertyTypes', event.target.value)} className="min-h-10 rounded-xl border border-slate-200 bg-white px-3 text-sm font-semibold normal-case tracking-normal text-slate-900">
              {propertyTypeOptions.map((option) => <option key={option || 'unknown-property-type'} value={option}>{option || 'Unknown'}</option>)}
            </select>
          </label>
          <div className="grid gap-3 sm:grid-cols-2">
            <label className="grid gap-1 text-xs font-semibold uppercase tracking-[0.12em] text-slate-400">
              Bedrooms
              <input value={draft.bedroomsMin} inputMode="numeric" pattern="[0-9]*" onChange={(event) => updateDraftField('bedroomsMin', normalizeMoneyInput(event.target.value))} className="min-h-10 rounded-xl border border-slate-200 bg-white px-3 text-sm font-semibold normal-case tracking-normal text-slate-900" placeholder="Min" />
            </label>
            <label className="grid gap-1 text-xs font-semibold uppercase tracking-[0.12em] text-slate-400">
              Bathrooms
              <input value={draft.bathroomsMin} inputMode="decimal" onChange={(event) => updateDraftField('bathroomsMin', normalizeNumericInput(event.target.value))} className="min-h-10 rounded-xl border border-slate-200 bg-white px-3 text-sm font-semibold normal-case tracking-normal text-slate-900" placeholder="Min" />
            </label>
          </div>
          <div className="grid gap-3 sm:grid-cols-2">
            <label className="grid gap-1 text-xs font-semibold uppercase tracking-[0.12em] text-slate-400">
              Urgency
              <select value={draft.urgency} onChange={(event) => updateDraftField('urgency', event.target.value)} className="min-h-10 rounded-xl border border-slate-200 bg-white px-3 text-sm font-semibold normal-case tracking-normal text-slate-900">
                <option value="">Unknown</option>
                {LEAD_REQUIREMENT_URGENCIES.map((option) => <option key={option} value={option}>{titleCaseLabel(option)}</option>)}
              </select>
            </label>
            <label className="grid gap-1 text-xs font-semibold uppercase tracking-[0.12em] text-slate-400">
              Needs to sell
              <select value={draft.needsToSell} onChange={(event) => updateDraftField('needsToSell', event.target.value)} className="min-h-10 rounded-xl border border-slate-200 bg-white px-3 text-sm font-semibold normal-case tracking-normal text-slate-900">
                <option value="">Unknown</option>
                <option value="true">Yes</option>
                <option value="false">No</option>
              </select>
            </label>
          </div>
          <label className="grid gap-1 text-xs font-semibold uppercase tracking-[0.12em] text-slate-400">
            Current property
            <select value={draft.currentPropertyStatus} onChange={(event) => updateDraftField('currentPropertyStatus', event.target.value)} className="min-h-10 rounded-xl border border-slate-200 bg-white px-3 text-sm font-semibold normal-case tracking-normal text-slate-900">
              {currentPropertyOptions.map((option) => <option key={option.value || 'unknown-current-property'} value={option.value}>{option.label}</option>)}
            </select>
          </label>
          {saveError ? <p className="rounded-2xl border border-rose-100 bg-rose-50 px-3 py-2 text-xs font-semibold text-rose-700">{saveError}</p> : null}
        </form>
      ) : (
        <dl className="mt-5 divide-y divide-slate-100">
          {profileRows.map((item) => (
            <div key={item.label} className="grid grid-cols-[minmax(0,0.8fr)_minmax(0,1fr)] gap-3 py-3 first:pt-0 last:pb-0">
              <dt className="inline-flex min-w-0 items-center gap-2 text-sm font-semibold text-slate-500">
                {createElement(item.icon, { size: 15, className: 'shrink-0 text-slate-400' })}
                <span className="truncate">{item.label}</span>
              </dt>
              <dd className="min-w-0 text-right text-sm font-semibold text-slate-950">{item.value || '—'}</dd>
            </div>
          ))}
        </dl>
      )}
      {showBondReferral ? (
        <div className="mt-5 rounded-3xl border border-emerald-100 bg-emerald-50/70 p-4">
          <p className="text-sm font-semibold text-emerald-900">Buyer may need prequalification help</p>
          <p className="mt-1 text-xs leading-5 text-emerald-700">If the buyer has agreed, log a handoff to the bond partner. No notification is sent automatically yet.</p>
          <button type="button" onClick={requestBondReferral} disabled={sendingBondReferral} className="mt-3 inline-flex min-h-10 w-full items-center justify-center gap-2 rounded-2xl bg-emerald-600 px-4 text-sm font-semibold text-white hover:bg-emerald-700 disabled:cursor-not-allowed disabled:bg-emerald-300">
            <Send size={15} />
            {sendingBondReferral ? 'Logging handoff...' : 'Send to Bond Partner'}
          </button>
          {bondReferralError ? <p className="mt-2 text-xs font-semibold text-rose-700">{bondReferralError}</p> : null}
        </div>
      ) : null}
      <button type="button" onClick={onRecommendations} className="mt-5 inline-flex min-h-11 w-full items-center justify-center gap-2 rounded-2xl border border-blue-100 bg-blue-50 px-4 text-sm font-semibold text-blue-700 hover:bg-blue-100">
        <Home size={15} />
        Listing recommendations
      </button>
    </section>
  )
}

function BuyerNextBestActionV2Card({ row, onNavigate, onConvert }) {
  const command = getBuyerWorkspaceCommand(row)
  const action = () => {
    if (command.actionId === 'convert') {
      onConvert?.()
      return
    }
    onNavigate?.(command.actionId || 'requirements')
  }
  return (
    <section className="relative overflow-hidden rounded-[28px] border border-amber-100 bg-[radial-gradient(circle_at_top_right,rgba(245,158,11,0.18),transparent_34%),linear-gradient(180deg,#FFFBEB,#FFFFFF)] p-7 shadow-[0_20px_42px_rgba(15,23,42,0.08)]">
      <div className="absolute right-5 top-5 flex h-14 w-14 items-center justify-center rounded-2xl border border-amber-100 bg-white/85 text-amber-600 shadow-sm">
        <AlertTriangle size={22} />
      </div>
      <div className="max-w-[82%]">
        <p className="text-xs font-semibold uppercase tracking-[0.18em] text-amber-600">Next Action</p>
        <h2 className="mt-4 text-3xl font-semibold leading-tight tracking-[-0.055em] text-slate-950">{command.title}</h2>
        <p className="mt-3 text-base leading-7 text-slate-600">{command.copy}</p>
      </div>
      {command.blockers?.length ? (
        <div className="mt-6 flex flex-wrap gap-2">
          {command.blockers.slice(0, 3).map((blocker) => (
            <span key={blocker} className="rounded-full border border-amber-100 bg-white/80 px-3 py-1.5 text-xs font-semibold text-amber-800">
              {blocker}
            </span>
          ))}
        </div>
      ) : null}
      <button type="button" onClick={action} className="mt-7 inline-flex min-h-12 w-full items-center justify-center gap-2 rounded-2xl bg-slate-950 px-5 text-sm font-semibold text-white shadow-[0_14px_28px_rgba(15,23,42,0.16)] hover:bg-slate-800">
        {command.actionLabel || 'Take action'}
        <ArrowRight size={16} />
      </button>
    </section>
  )
}

function BuyerFollowUpCentreCard({ row, leadScore, organisationId, actor, onSaved, onNavigate }) {
  const summary = getBuyerFollowUpSummary(row, leadScore)
  const [activeListings, setActiveListings] = useState([])
  const [listingsLoading, setListingsLoading] = useState(false)
  const [propertyToLinkId, setPropertyToLinkId] = useState('')
  const [locallyLinkedIds, setLocallyLinkedIds] = useState([])
  const [linkingProperty, setLinkingProperty] = useState(false)
  const [linkError, setLinkError] = useState('')
  const [linkMessage, setLinkMessage] = useState('')
  const propertyOptions = useMemo(
    () => buildAppointmentPropertyOptions(row, activeListings).map((option) =>
      locallyLinkedIds.includes(option.id) ? { ...option, source: option.source === 'Active listing' ? 'Shortlist' : option.source, isLeadLinked: true } : option,
    ),
    [activeListings, locallyLinkedIds, row],
  )
  const selectedProperty = propertyOptions.find((option) => option.id === propertyToLinkId) || null
  const linkedPropertyCount = propertyOptions.filter((option) => option.isLeadLinked !== false).length
  const selectedPropertyAlreadyLinked = Boolean(selectedProperty && selectedProperty.isLeadLinked !== false)
  const quickActions = [
    { label: 'Log Call', icon: Phone, action: 'activity' },
    { label: 'Log WhatsApp', icon: MessageSquarePlus, action: 'activity' },
    { label: 'Schedule Viewing', icon: CalendarDays, action: 'appointments' },
    { label: 'Send Listings', icon: Home, action: 'property_match' },
  ]

  useEffect(() => {
    if (!organisationId) return undefined
    let cancelled = false
    async function loadListings() {
      try {
        setListingsLoading(true)
        setLinkError('')
        const result = await listSearchablePrivateListings({ organisationId })
        if (!cancelled) setActiveListings(Array.isArray(result) ? result.slice(0, 40) : [])
      } catch (loadError) {
        if (!cancelled) {
          setActiveListings([])
          setLinkError(loadError?.message || 'Unable to load listings for this buyer.')
        }
      } finally {
        if (!cancelled) setListingsLoading(false)
      }
    }
    void loadListings()
    return () => {
      cancelled = true
    }
  }, [organisationId])

  useEffect(() => {
    setPropertyToLinkId((current) => {
      if (current && propertyOptions.some((option) => option.id === current)) return current
      return propertyOptions.find((option) => option.isLeadLinked === false)?.id || propertyOptions[0]?.id || ''
    })
  }, [propertyOptions])

  async function linkSelectedProperty() {
    if (!selectedProperty) {
      setLinkError('Choose a property to link to this buyer.')
      return
    }

    if (selectedPropertyAlreadyLinked) {
      setLinkError('')
      setLinkMessage(`${selectedProperty.label} is already linked to this buyer.`)
      return
    }

    try {
      setLinkingProperty(true)
      setLinkError('')
      setLinkMessage('')
      await upsertLeadListingInterest(
        {
          organisationId,
          lead: row,
          contactId: getLeadContactId(row),
          listing: {
            ...selectedProperty,
            listingId: selectedProperty.id,
            title: selectedProperty.label,
            propertyAddress: selectedProperty.address || selectedProperty.description,
            askingPrice: selectedProperty.price,
            sellerName: selectedProperty.sellerName,
            sellerEmail: selectedProperty.sellerEmail,
            sellerPhone: selectedProperty.sellerPhone,
          },
          source: 'follow_up_centre',
          status: 'shortlisted',
          isOriginalEnquiry: false,
          isAgentSelected: true,
          createdBy: actor?.id,
          notes: 'Linked from the buyer follow-up centre.',
        },
        { actor },
      )
      setLocallyLinkedIds((current) => current.includes(selectedProperty.id) ? current : [...current, selectedProperty.id])
      setLinkMessage(`${selectedProperty.label} linked to this buyer.`)
      await onSaved?.()
    } catch (saveError) {
      setLinkError(saveError?.message || 'Unable to link this property to the buyer.')
    } finally {
      setLinkingProperty(false)
    }
  }

  return (
    <section className={`${buyerWorkspaceCardClass} p-5`}>
      <div>
        <p className="flex items-center gap-2 text-xs font-semibold uppercase tracking-[0.14em] text-slate-500">
          <Phone size={15} />
          Follow-Up Centre
        </p>
        <h2 className="mt-2 text-xl font-semibold tracking-[-0.04em] text-slate-950">Stay in touch</h2>
        <p className="mt-1 text-sm text-slate-500">Consistency converts interest into viewings and offers.</p>
      </div>
      <dl className="mt-5 grid grid-cols-2 overflow-hidden rounded-2xl border border-slate-200 bg-slate-50">
        <div className="border-b border-r border-slate-200 p-3">
          <dt className="text-xs font-semibold text-slate-500">Last Contact</dt>
          <dd className="mt-1 text-sm font-semibold text-slate-950">{summary.lastContact}</dd>
        </div>
        <div className="border-b border-slate-200 p-3">
          <dt className="text-xs font-semibold text-slate-500">Next Follow-Up</dt>
          <dd className="mt-1 text-sm font-semibold text-slate-950">{summary.nextFollowUp}</dd>
        </div>
        <div className="border-r border-slate-200 p-3">
          <dt className="text-xs font-semibold text-slate-500">Days Since Contact</dt>
          <dd className="mt-1 text-sm font-semibold text-slate-950">{summary.daysSinceContact}</dd>
        </div>
        <div className="p-3">
          <dt className="text-xs font-semibold text-slate-500">Buyer Temperature</dt>
          <dd className="mt-1 text-sm font-semibold text-amber-600">{summary.temperature}</dd>
        </div>
      </dl>
      <div className="mt-5 grid grid-cols-2 gap-2">
        {quickActions.map((item) => (
          <button key={item.label} type="button" onClick={() => onNavigate?.(item.action)} className="inline-flex min-h-11 items-center justify-center gap-2 rounded-2xl border border-slate-200 bg-white px-3 text-sm font-semibold text-slate-700 hover:bg-slate-50">
            {createElement(item.icon, { size: 15 })}
            {item.label}
          </button>
        ))}
      </div>
      <div className="mt-5 grid gap-3 rounded-2xl border border-blue-100 bg-blue-50/50 p-3">
        <div className="flex flex-wrap items-center justify-between gap-2">
          <div>
            <p className="text-sm font-semibold text-slate-950">Link property to buyer</p>
            <p className="mt-0.5 text-xs font-medium text-slate-500">{linkedPropertyCount} linked propert{linkedPropertyCount === 1 ? 'y' : 'ies'} on this lead.</p>
          </div>
          <StatusPill tone={linkedPropertyCount ? 'blue' : 'slate'}>{linkedPropertyCount || 0} linked</StatusPill>
        </div>
        <div className="grid gap-2 md:grid-cols-[minmax(0,1fr)_auto] md:items-center">
          <PropertySelector
            value={propertyToLinkId}
            onChange={setPropertyToLinkId}
            properties={propertyOptions}
            placeholder={listingsLoading ? 'Loading listings...' : 'Search listings to link'}
            disabled={listingsLoading || linkingProperty || !propertyOptions.length}
            onAddProperty={() => onNavigate?.('property_match')}
          />
          <button
            type="button"
            onClick={linkSelectedProperty}
            disabled={listingsLoading || linkingProperty || !selectedProperty}
            className="inline-flex min-h-12 items-center justify-center gap-2 rounded-2xl bg-blue-600 px-4 text-sm font-semibold text-white hover:bg-blue-700 disabled:cursor-not-allowed disabled:bg-slate-300"
          >
            <Plus size={15} />
            {linkingProperty ? 'Linking...' : selectedPropertyAlreadyLinked ? 'Already Linked' : 'Link Property'}
          </button>
        </div>
        {linkError ? <p className="rounded-xl border border-rose-100 bg-rose-50 px-3 py-2 text-xs font-semibold text-rose-700">{linkError}</p> : null}
        {linkMessage ? <p className="rounded-xl border border-emerald-100 bg-emerald-50 px-3 py-2 text-xs font-semibold text-emerald-700">{linkMessage}</p> : null}
      </div>
    </section>
  )
}

