function getBuyerPropertyEnquiry(row = {}) {
  const matchedFields = row.rawEnquiryPayload?.parser?.matchedFields && typeof row.rawEnquiryPayload.parser.matchedFields === 'object'
    ? row.rawEnquiryPayload.parser.matchedFields
    : {}
  const reference = normalizeText(row.sourceReferenceId || row.source_reference_id || matchedFields.listingReference || matchedFields.webRef)
  const propertyInterest = normalizeText(row.propertyInterest || row.property_interest || matchedFields.propertyInterest || matchedFields.development)
  const title = normalizeText(row.enquiredPropertyTitle || row.enquired_property_title || matchedFields.propertyTitle) ||
    [propertyInterest, reference].filter(Boolean).join(' - ')
  const address = normalizeText(row.enquiredPropertyAddress || row.enquired_property_address || matchedFields.propertyAddress || row.areaInterest || row.area_interest)
  const price = row.enquiredPropertyPrice ?? row.enquired_property_price ?? matchedFields.propertyPrice
  const hasData = title || address || normalizeText(price)
  if (!hasData) {
    return { title: 'No property linked', address: '—', price: '—' }
  }
  const formattedPrice = price === null || price === undefined || price === '' ? '—' : formatCurrency(price)
  return {
    title: title || reference || 'Property enquiry',
    address: address || '—',
    price: formattedPrice,
  }
}

function getBuyerEnquiryPricePoint(lead = {}) {
  const directPrice = toFiniteNumber(
    lead.enquiredPropertyPrice ??
      lead.enquired_property_price ??
      lead.enquiryPrice ??
      lead.enquiry_price,
  )
  if (directPrice) return directPrice
  const originalInterest = (Array.isArray(lead.listingInterests) ? lead.listingInterests : []).find((interest) => interest?.isOriginalEnquiry || interest?.is_original_enquiry)
  const originalListing = originalInterest?.listing || null
  const originalPrice = toFiniteNumber(originalListing?.price ?? originalListing?.askingPrice ?? originalListing?.asking_price)
  return originalPrice || 0
}

const BUYER_ENQUIRY_PRICE_MATCH_BAND = 1000000

function getPriceBandQuickMatchContext(lead = {}, band = BUYER_ENQUIRY_PRICE_MATCH_BAND) {
  const pricePoint = getBuyerEnquiryPricePoint(lead)
  if (!pricePoint) {
    return {
      mode: 'latest',
      pricePoint: 0,
      minPrice: '',
      maxPrice: '',
      title: 'Latest listing recommendations',
      description: 'No enquiry price is available yet, so we are showing the latest listings in the workspace.',
    }
  }
  return {
    mode: 'price_band',
    pricePoint,
    minPrice: Math.max(0, pricePoint - band),
    maxPrice: pricePoint + band,
    title: 'Price Band Quick Match',
    description: `Listings within ${formatCurrency(Math.max(0, pricePoint - band))} - ${formatCurrency(pricePoint + band)} based on the enquired price point.`,
  }
}

function isQuickMatchListingAvailable(listing = {}) {
  const status = normalizeText(listing.status || listing.listingStatus || listing.listing_status).toLowerCase()
  if (['sold', 'archived', 'withdrawn', 'converted', 'removed', 'inactive', 'expired'].some((token) => status.includes(token))) return false
  return true
}

function getSellerAddress(row = {}) {
  const firstLine = normalizeText(
    row.sellerPropertyAddress ||
    row.seller_property_address ||
    row.propertyAddress ||
    row.address ||
    row.addressLine1 ||
    '',
  )
  const secondLine = normalizeText(row.areaInterest || row.area_interest || row.suburb || row.city || '')
  const lines = [firstLine].filter(Boolean)
  if (secondLine && !firstLine.toLowerCase().includes(secondLine.toLowerCase())) {
    lines.push(secondLine)
  }
  if (!lines.length) {
    return { first: 'Address Pending', second: '—' }
  }
  return { first: lines[0], second: lines[1] || '—' }
}

